#define BLOCK_SIZE 256
#define HALO 1

#define IN_RANGE(x, min, max) ((x)>=((min)) && (x)<=((max)))
#define MIN(a, b) ((a)<=((b)) ? (a) : (b))

kernel void dynproc_kernel(
                int iteration, 
                global const int *gpuWall,
                global const int *gpuSrc,
                global int *gpuResults,
                int cols, 
                int rows,
                int startStep,
                int border,
                int theHalo,
                local int* prev,
                local int* result,
                global int* d_outputBuffer)
{
	int bx = blockIdx.x;
	int tx=threadIdx.x;

	int small_block_cols = BLOCK_SIZE-iteration*theHalo*2;

	int blkX = small_block_cols*bx-border;
	int blkXmax = blkX+BLOCK_SIZE-1;

	int xidx = blkX+tx;

	int validXmin = (blkX < 0) ? -blkX : 0;
	int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

	int W = tx-1;
	int E = tx+1;

	W = (W < validXmin) ? validXmin : W;
	E = (E > validXmax) ? validXmax : E;

	bool isValid = IN_RANGE(tx, validXmin, validXmax);

	if(IN_RANGE(xidx, 0, cols-1)){
            prev[tx] = gpuSrc[xidx];
	} else {
            prev[tx] = 0;
        }
	barrier(CLK_LOCAL_MEM_FENCE); 
        bool computed;
        for (int i=0; i<iteration ; i++){ 
            computed = false;
            if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) &&  \
                  isValid){
                  computed = true;
                  int left = prev[W];
                  int up = prev[tx];
                  int right = prev[E];
                  int shortest = MIN(left, up);
                  shortest = MIN(shortest, right);
                  int index = cols*(startStep+i)+xidx;
                  result[tx] = shortest + gpuWall[index];

            }
            barrier(CLK_LOCAL_MEM_FENCE);
            if(i==iteration-1)
                break;
            if(computed)	 
                prev[tx]= result[tx];
	    barrier(CLK_LOCAL_MEM_FENCE); 
      }


      if (IN_RANGE(xidx, 0, cols-1) && computed){
          gpuResults[xidx]=result[tx];		
      }
}
